import logging
import json
import urllib.request
import urllib.error
import os
import requests
import getpass
import time

def fetch_hiking_data(wkt_text, crs, method, url, timeout=30, use_requests=True):
    """
    Function to fetch hiking data from the given web service.
    
    Args:
        wkt_text (str): The WKT (Well-Known Text) representation of geometry
        crs (str): Coordinate Reference System identifier
        method (str): The calculation method to use
        url (str): The API endpoint URL
        timeout (int, optional): Timeout in seconds for the request. Defaults to 30.
        use_requests (bool, optional): Use requests library instead of urllib. Defaults to True.
        
    Returns:
        dict or None: The JSON response data if successful, None otherwise
    """
    post_data = {
        "name": "wegzeit",
        "polygonzug": wkt_text,
        "crs": crs,
        "methode": method,
        "output": "jsondownload"
    }
    
    # Get proxy credentials if needed
    proxy_user = os.environ.get('PROXY_USER')
    proxy_pass = os.environ.get('PROXY_PASS')
    
    # Get proxy settings from environment
    http_proxy = os.environ.get('HTTP_PROXY') or os.environ.get('http_proxy')
    https_proxy = os.environ.get('HTTPS_PROXY') or os.environ.get('https_proxy')
    
    # Add authentication to proxy URLs if needed
    if proxy_user and proxy_pass:
        if http_proxy and '://' in http_proxy:
            http_proxy = http_proxy.replace('://', f'://{proxy_user}:{proxy_pass}@')
        if https_proxy and '://' in https_proxy:
            https_proxy = https_proxy.replace('://', f'://{proxy_user}:{proxy_pass}@')
    
    # Start timing
    start_time = time.time()
    print(f"Starting request at {time.ctime()}")
    
    if use_requests:
        # Use the requests library
        proxies = {}
        if http_proxy:
            proxies['http'] = http_proxy
        if https_proxy:
            proxies['https'] = https_proxy
            
        if proxies:
            print(f"Using proxies with requests: {proxies}")
        
        try:
            response = requests.post(
                url, 
                json=post_data,
                headers={'Content-Type': 'application/json'},
                proxies=proxies,
                timeout=timeout
            )
            
            elapsed = time.time() - start_time
            print(f"Response received in {elapsed:.2f} seconds")
            
            if response.status_code == 200:
                try:
                    return response.json()
                except ValueError as e:
                    logging.warning(f"Error decoding JSON response: {str(e)}")
                    return None
            else:
                logging.warning(f"Request failed with status code {response.status_code}")
                return None
                
        except requests.exceptions.Timeout:
            elapsed = time.time() - start_time
            logging.error(f"Request timed out after {elapsed:.2f} seconds")
            return None
        except requests.exceptions.RequestException as e:
            elapsed = time.time() - start_time
            logging.error(f"Request error after {elapsed:.2f} seconds: {str(e)}")
            return None
    else:
        # Use urllib
        # Format data as JSON
        data = json.dumps(post_data).encode('utf-8')
        
        # Setup proxy handler
        proxies = {}
        if http_proxy:
            proxies['http'] = http_proxy
        if https_proxy:
            proxies['https'] = https_proxy
            
        if proxies:
            print(f"Using proxies with urllib: {proxies}")
            
        proxy_handler = urllib.request.ProxyHandler(proxies)
        opener = urllib.request.build_opener(proxy_handler)
        urllib.request.install_opener(opener)
        
        # Create request
        req = urllib.request.Request(
            url, 
            data=data,
            headers={'Content-Type': 'application/json'},
        )
        
        try:
            with urllib.request.urlopen(req, timeout=timeout) as response:
                elapsed = time.time() - start_time
                print(f"Response received in {elapsed:.2f} seconds")
                
                if response.getcode() == 200:
                    try:
                        response_data = response.read().decode('utf-8')
                        return json.loads(response_data)
                    except ValueError as e:
                        logging.warning(f"Error decoding JSON response: {str(e)}")
                        return None
                else:
                    logging.warning(f"Request failed with status code {response.getcode()}")
                    return None
        except urllib.error.URLError as e:
            elapsed = time.time() - start_time
            logging.error(f"URL error after {elapsed:.2f} seconds: {str(e)}")
            return None
        except urllib.error.HTTPError as e:
            elapsed = time.time() - start_time
            logging.error(f"HTTP error after {elapsed:.2f} seconds: {e.code} - {e.reason}")
            return None
        except Exception as e:
            elapsed = time.time() - start_time
            logging.error(f"Unexpected error after {elapsed:.2f} seconds: {str(e)}")
            return None
      
